INSERT INTO `v1_a0f5ef118a6d7533240f0c62f2e47d5355945056b68e23e77792a898a6d732d3` VALUES (10001, 1000101, "vo_minigame_1004_top_1_000", 1, 2, "ふっふっふ、これでカヤぴぃとボスを見返してやるです！", "vo_minigame_1004");
